const EventEmitter = require('events');

class EventSystem extends EventEmitter {}

const eventSystem = new EventSystem();

// Listener for 'orderPlaced' event
eventSystem.on('orderPlaced', (order) => {
  console.log(`Order received: ${order.id} for ${order.product}`);
});

// Emitting the 'orderPlaced' event
eventSystem.emit('orderPlaced', { id: 123, product: 'Book' });

