const redis = require('redis');
const publisher = redis.createClient();

publisher.connect();

async function publishOrder() {
  const order = { id: 101, product: 'Keyboard' };
  await publisher.publish('orders', JSON.stringify(order));
  console.log('Order published:', order);
  await publisher.quit();
}
publishOrder();

// subscriber.js
const redis = require('redis');
const subscriber = redis.createClient();

(async () => {
  await subscriber.connect();
  await subscriber.subscribe('orders', (message) => {
    const order = JSON.parse(message);
    console.log(`Received order: ${order.id} for ${order.product}`);
  });
})();

function createButton() {
  const button = document.createElement('button');
  button.textContent = 'Click me';

  // This event listener holds a reference to `button` preventing garbage collection
  button.addEventListener('click', function() {
    alert('Button clicked!');
  });

  document.body.appendChild(button);
  return button;
}

let btn = createButton();

// Later we remove the button from the DOM
document.body.removeChild(btn);

// However, if we don't remove the event listener, the button is still referenced.
// This causes a memory leak.

function createButton() {
  const button = document.createElement('button');
  button.textContent = 'Click me';

  function onClick() {
    alert('Button clicked!');
  }

  button.addEventListener('click', onClick);

  document.body.appendChild(button);
  return { button, onClick };
}

const { button, onClick } = createButton();

// When cleaning up:
button.removeEventListener('click', onClick);
document.body.removeChild(button);

